// Package imports:
import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';

enum ExtendedZoomType {
  superZoom,
  zoom,
  wide,
  superWide,
  ;

  // - superZoom : Telephoto × zoom 1.99x
  // - zoom      : Telephoto × zoom 1.0x
  // - wide      : WideAngle × zoom 1.99x
  // - superWide : WideAngle × zoom 1.0x
  static ExtendedZoomType? fromLensAndZoom({
    required Lens currentLens,
    required double currentZoom,
    required double maxZoom,
    required double minZoom,
  }) {
    // 小数第2位までの一致を判定
    final currentRounded = (currentZoom * 100).round() / 100;
    final maxRounded = (maxZoom * 100).round() / 100;
    final minRounded = (minZoom * 100).round() / 100;

    if (currentLens.isTelephoto) {
      if (currentRounded == maxRounded) {
        return ExtendedZoomType.superZoom;
      } else if (currentRounded == minRounded) {
        return ExtendedZoomType.zoom;
      }
    } else if (currentLens.isWideAngle) {
      if (currentRounded == maxRounded) {
        return ExtendedZoomType.wide;
      } else if (currentRounded == minRounded) {
        return ExtendedZoomType.superWide;
      }
    }
    return null;
  }
}

