import 'package:flutter_test/flutter_test.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';
import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/camera_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/analysis_type.dart';
import 'package:baseball_detector_flutter/data/models/enums/camera_mode.dart';
import 'package:baseball_detector_flutter/data/models/enums/extended_zoom_type.dart';
import 'package:baseball_detector_flutter/data/profile_storage_fake.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import '../_common/mock_knowhere_configurable_camera.dart';

void main() {
  TestWidgetsFlutterBinding.ensureInitialized();

  late ProviderContainer container;
  late FakeProfileStorage fakeProfileStorage;
  late MockKnowhereConfigurableCamera mockCameraApi;
  late CameraState cameraState;

  setUp(() {
    fakeProfileStorage = FakeProfileStorage();
    mockCameraApi = MockKnowhereConfigurableCamera();
    container = ProviderContainer(
      overrides: [
        profileStorageProvider.overrideWithValue(fakeProfileStorage),
        cameraControllerProvider
            .overrideWith(() => CameraController(cameraAPI: mockCameraApi)),
      ],
    );
    cameraState = CameraState(
      analysisType: AnalysisType.pitching,
      cameraMode: CameraMode.auto,
      isStabilizationAvailable: true,
      isTelephotoAvailable: false,
      telephotoLensList: [],
      wideAngleLensList: [Lens(0, 'WideAngle')],
      longsideAngleOfView: 30.0,
      minZoom: CameraState.defaultMinZoom,
      maxZoom: CameraState.defaultMaxZoom,
      minISO: 100,
      maxISO: 5000,
      minShutterSpeed: 5000,
      maxShutterSpeed: 5000,
      minFocus: CameraState.defaultMinZoom,
      maxFocus: CameraState.defaultMaxZoom,
      isFocusModeAuto: true,
      focus: CameraState.defaultMinZoom,
      zoom: CameraState.defaultMinZoom,
      lens: Lens(0, 'WideAngle'),
      format: dummyFormatList[18],
      lensList: [Lens(0, 'WideAngle')],
      formatList: dummyFormatList,
      iso: 100,
      shutterSpeed: 5000,
