    );

    test(
      'setISOがcameraAPI.setISO を呼ぶ',
      () async {
        final controller = container.read(cameraControllerProvider.notifier);

        await controller.setISO(200.0);
        final result = await mockCameraApi.getISO();

        expect(result, 200.0);
      },
    );

    test(
      'setShutterSpeedがcameraAPI.setShutterSpeed を呼ぶ',
      () async {
