    test(
      'setFocusModeToAutoがcameraAPI.setFocusModeToAutoとprofileStorage.setCameraAutoFocusMode(true)を呼ぶ',
      () async {
        final controller = container.read(cameraControllerProvider.notifier);

        await controller.setFocusModeToAuto();
        final result = await mockCameraApi.isAutoFocus();
        expect(result, true);
