   426→  Future<void> _updateNativeParameters() async {
   427→    final (
   428→      iso,
   429→      shutterSpeed,
   430→      lens,
   431→      isFocusModeAuto,
   432→      focus,
   433→      zoom,
   434→      format,
   435→      minZoom,
   436→      maxZoom,
   437→    ) = await (
   438→      getISO(),
   439→      getShutterSpeed(),
   440→      getLensIndex().then((idx) async {
   441→        final lensList = await getLensList();
   442→        if (lensList != null &&
   443→            idx != null &&
   444→            idx >= 0 &&
   445→            idx < lensList.length) {
   446→          return lensList[idx];
   447→        }
   448→        return null;
   449→      }),
   450→      isAutoFocus(),
   451→      getFocus(),
   452→      getZoom(),
   453→      getFormatIndex().then((idx) async {
   454→        final formatList = await getFormatList();
   455→        if (formatList != null &&
   456→            idx != null &&
   457→            idx >= 0 &&
   458→            idx < formatList.length) {
   459→          return formatList[idx];
   460→        }
   461→        return null;
   462→      }),
   463→      getMinZoom(),
   464→      getMaxZoom(),
   465→    ).wait;
   466→
   467→    final (
   468→      minFocus,
   469→      maxFocus,
   470→      minISO,
   471→      maxISO,
   472→      minShutterSpeed,
   473→      maxShutterSpeed,
   474→      lensList,
   475→      formatList,
   476→    ) = await (
   477→      getMinFocus(),
   478→      getMaxFocus(),
   479→      getMinISO(),
   480→      getMaxISO(),
   481→      getMinShutterSpeed(),
   482→      getMaxShutterSpeed(),
   483→      getLensList(),
   484→      getFormatList(),
   485→    ).wait;
   486→
   487→    // 追加: NativeParametersの全更新
   488→    final isStabilizationAvailable = await isStabilizationSupportedDevice();
   489→    final telephotoLensList = lensList == null
   490→        ? <Lens>[]
   491→        : lensList.where((lens) => lens.isTelephoto).toList();
   492→    final wideAngleLensList = lensList == null
   493→        ? <Lens>[]
   494→        : lensList.where((lens) => lens.isWideAngle).toList();
   495→    final isTelephotoAvailable = telephotoLensList.isNotEmpty;
   496→
   497→    final extendedZoom =
   498→        (lens != null && zoom != null && minZoom != null && maxZoom != null)
   499→            ? ExtendedZoomType.fromLensAndZoom(
   500→                currentLens: lens,
   501→                currentZoom: zoom,
   502→                minZoom: minZoom,
   503→                maxZoom: maxZoom,
   504→              )
   505→            : null;
   506→
   507→    state = state.copyWith(
   508→      minZoom: minZoom,
   509→      maxZoom: maxZoom,
   510→      minFocus: minFocus,
   511→      maxFocus: maxFocus,
   512→      minISO: minISO,
   513→      maxISO: maxISO,
   514→      minShutterSpeed: minShutterSpeed,
   515→      maxShutterSpeed: maxShutterSpeed,
   516→      lensList: lensList,
   517→      formatList: formatList,
   518→      iso: iso,
   519→      shutterSpeed: shutterSpeed,
   520→      lens: lens,
   521→      isFocusModeAuto: isFocusModeAuto,
   522→      focus: focus,
   523→      zoom: zoom,
   524→      extendedZoom: extendedZoom,
   525→      format: format,
   526→      // 追加分
   527→      isStabilizationAvailable: isStabilizationAvailable,
   528→      telephotoLensList: telephotoLensList,
   529→      wideAngleLensList: wideAngleLensList,
   530→      isTelephotoAvailable: isTelephotoAvailable,
   531→    );
   532→  }
