   656→  Future<String?> startRecording() async {
   657→    try {
   658→      _isAutoExposure = await isAutoExposure();
   659→      await tearDownAutoExposureObserver();
   660→
   661→      if (_currentSession == null) {
   662→        throw Exception();
   663→      }
   664→
   665→      final accelerationController =
   666→          AccelerationController.getSingletonObject();
   667→      final orientation = await NativeDeviceOrientationCommunicator()
   668→          .orientation(useSensor: false);
   669→      accelerationController.setOrientation(orientation);
   670→
   671→      final now = DateTime.now(); // NOTE: It's local time
   672→      final fileName = now
   673→          .toString()
   674→          .replaceAll(' ', '_'); // extension is decided by native side.
   675→      await Directory(_currentSession!.directory).create(recursive: true);
   676→      final filePath = join(
   677→          _currentSession!.directory, _sanitizeRecordingFileName(fileName));
   678→
   679→      accelerationController.reset();
   680→      accelerationController.start();
   681→
   682→      _currentSession!.recordingFilePath =
   683→          await cameraAPI.startRecording(filePath);
   684→      return _currentSession!.recordingFilePath;
   685→    } catch (e, stacktrace) {
   686→      _logger.e('Failed to start recording', ex: e, stacktrace: stacktrace);
   687→      rethrow;
   688→    }
   689→  }
