   718→  Future<LocalVideoData> stopRecordingAndSaveToLocalStorage(
   719→    UnitType unit,
   720→  ) async {
   721→    try {
   722→      setUpAutoExposureObserver();
   723→
   724→      if (_currentSession == null ||
   725→          _currentSession!.recordingFilePath == null) {
   726→        throw Exception();
   727→      }
   728→      await cameraAPI.stopRecording();
   729→
   730→      final accelerationController =
   731→          AccelerationController.getSingletonObject();
   732→      accelerationController.stop();
   733→
   734→      final longsideAngleOfView = await getLongsideAngleOfView();
   735→      assert(longsideAngleOfView != null);
   736→      final accX = accelerationController.averageX;
   737→      final accY = accelerationController.averageY;
   738→      final accZ = accelerationController.averageZ;
   739→      final lensList = await getLensList();
   740→      final lensIndex =
   741→          (await getLensIndex())?.clamp(0, (lensList?.length ?? 1) - 1);
   742→      final lens =
   743→          (lensList != null && lensIndex != null) ? lensList[lensIndex] : null;
   744→
   745→      final (focus, isAutoFocus, zoom, iso, shutterSpeed) = await (
   746→        getFocus(),
   747→        this.isAutoFocus(),
   748→        getZoom(),
   749→        getISO(),
   750→        getShutterSpeed(),
   751→      ).wait;
   752→
   753→      ExtendedZoomType? extendedZoomType;
   754→      if (lens != null &&
   755→          zoom != null &&
   756→          state.minZoom != null &&
   757→          state.maxZoom != null) {
   758→        extendedZoomType = ExtendedZoomType.fromLensAndZoom(
   759→          currentLens: lens,
   760→          currentZoom: zoom,
   761→          minZoom: state.minZoom!,
   762→          maxZoom: state.maxZoom!,
   763→        );
   764→      }
   765→
   766→      final deviceInfo = DeviceInfoPlugin();
   767→      final device = platform.isAndroid
   768→          ? (await deviceInfo.androidInfo).model
   769→          : (await deviceInfo.iosInfo).utsname.fixedProductName();
   770→
   771→      final localVideoListController =
   772→          ref.read(localVideoListControllerProvider.notifier);
   773→      LocalVideoData? newData;
   774→
   775→      final teamId = profileStorage.getTeamId()!;
   776→
   777→      // NOTE: The method cameraAPI.stopRecording returns before completes saving a video file.
   778→      // TODO: Refactor knowhere_configurable_camera to wait completing.
   779→      await Future.delayed(const Duration(milliseconds: 500), () async {
   780→        newData = await localVideoListController.addFile(
