  1022→  /// シンプルに「一番良いフルHDフォーマット」を返す
  1023→  /// 1. フルHDかつ120FPS未満だけ抽出
  1024→  /// 2. 最大FPSを求める
  1025→  /// 3. 非HDRかつ非Binnedを最優先
  1026→  /// 4. 非Binnedを次点で
  1027→  /// 5. それもなければ最初のもの
  1028→  Format? selectBestFullHDFormat(List<Format> formatList) {
  1029→    // 1. フルHDかつ120FPS未満だけ抽出
  1030→    final fullHDFormats =
  1031→        formatList.where((f) => f.isFullHD && f.fps < 120).toList();
  1032→
  1033→    if (fullHDFormats.isEmpty) return null;
  1034→
  1035→    // 2. 最大FPSを求める
  1036→    final maxFps =
  1037→        fullHDFormats.map((f) => f.fps).reduce((a, b) => a > b ? a : b);
  1038→    final maxFpsFormats = fullHDFormats.where((f) => f.fps == maxFps).toList();
  1039→
  1040→    // 3. 非HDRかつ非Binnedを最優先
  1041→    final best = maxFpsFormats.where((f) => !f.hdr && !f.binned);
  1042→    if (best.isNotEmpty) return best.first;
  1043→
  1044→    // 4. 非Binnedを次点で
  1045→    final nonBinned = maxFpsFormats.where((f) => !f.binned);
  1046→    if (nonBinned.isNotEmpty) return nonBinned.first;
  1047→
  1048→    // 5. それもなければ最初のもの
  1049→    return maxFpsFormats.first;
  1050→  }
