/// {@category Controllers}
library;

// Dart imports:
import 'dart:async';
import 'dart:io';
import 'dart:math';

// Flutter imports:
import 'package:flutter/widgets.dart';

// Package imports:
import 'package:device_info_plus/device_info_plus.dart';
import 'package:fimber/fimber.dart';
import 'package:knowhere_configurable_camera/knowhere_configurable_camera.dart';
import 'package:native_device_orientation/native_device_orientation.dart';
import 'package:path/path.dart';
import 'package:permission_handler/permission_handler.dart';
import 'package:riverpod_annotation/riverpod_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/acceleration_controller.dart';
import 'package:baseball_detector_flutter/controllers/local_video_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/analysis_type.dart';
import 'package:baseball_detector_flutter/data/models/enums/camera_mode.dart';
import 'package:baseball_detector_flutter/data/models/enums/extended_zoom_type.dart';
import 'package:baseball_detector_flutter/data/models/enums/unit_type.dart';
import 'package:baseball_detector_flutter/data/models/local_video.dart';
import 'package:baseball_detector_flutter/data/profile_storage.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/apple_product_name_ext.dart';
import 'package:baseball_detector_flutter/utils/environment.dart';
import 'package:baseball_detector_flutter/utils/platform.dart' as platform;
import 'package:baseball_detector_flutter/utils/platform.dart';
import 'package:baseball_detector_flutter/utils/sanitize_file_name.dart';

part 'camera_controller.g.dart';

class RecordingSession {
  final String sessionId;
  final String directory;
  String? recordingFilePath;

  RecordingSession({
    required this.sessionId,
    required this.directory,
    this.recordingFilePath,
  });
}

@immutable
class CameraState {
  // iPhone 17 Pro で zoom 2.0 以上 & 低照度で紫色のフィルターがかかる減少があるため
  // 2.0 ではなく 1.99
  static const defaultMaxZoom = 1.99;
  static const defaultMinZoom = 1.00;

  /// ISO感度（マニュアル時にユーザーが変更可能）
  final double? iso;

  /// シャッタースピード（マニュアル時にユーザーが変更可能）
  final double? shutterSpeed;

  /// 選択中のレンズ（ユーザーが選択可能）
  final Lens? lens;

  /// フォーカスモード（AF/MF、ユーザーが切替可能）
  final bool? isFocusModeAuto;

  /// フォーカス値（MF時にユーザーが変更可能）
  final double? focus;

  /// ズーム値（ユーザーが変更可能）
  final double? zoom;

  /// フォーマット（ユーザーが選択可能）
  final Format? format;

  /// 手ブレ補正が利用可能か
  final bool isStabilizationAvailable;

  /// 望遠レンズが利用可能か
  final bool? isTelephotoAvailable;

  /// 望遠レンズリスト
  final List<Lens> telephotoLensList;

  /// 広角レンズリスト
  final List<Lens> wideAngleLensList;

  /// レンズの視野角
  final double? longsideAngleOfView;

  /// ズームの最小値
  final double? minZoom;

  /// ズームの最大値
  final double? maxZoom;

  /// フォーカスの最小値
  final double? minFocus;

  /// フォーカスの最大値
  final double? maxFocus;

  /// ISOの最小値
  final double? minISO;

  /// ISOの最大値
  final double? maxISO;

  /// シャッタースピードの最小値
  final double? minShutterSpeed;

  /// シャッタースピードの最大値
  final double? maxShutterSpeed;

  /// 利用可能なレンズリスト
  final List<Lens>? lensList;

  /// 利用可能なフォーマットリスト
  final List<Format>? formatList;

  /// 分析タイプ（投球/打撃など、ユーザーが選択可能）
  final AnalysisType analysisType;

  /// カメラモード（AUTO/MANUAL、ユーザーが選択可能）
  final CameraMode? cameraMode;

  /// 拡張ズーム種別（アプリ内計算値）
  final ExtendedZoomType? extendedZoom;

  /// フォーカスマグニファイア（ルーペ）の有効/無効状態
  final bool focusMagnifierEnabled;

  const CameraState({
    // Not Native API 由来・ユーザー操作可
    required this.analysisType,
    required this.cameraMode,
    // Native API 由来・ユーザー操作不可
    required this.isStabilizationAvailable,
    required this.isTelephotoAvailable,
    required this.telephotoLensList,
    required this.wideAngleLensList,
    required this.longsideAngleOfView,
    required this.minZoom,
    required this.maxZoom,
    required this.minFocus,
    required this.maxFocus,
    required this.minISO,
    required this.maxISO,
    required this.minShutterSpeed,
    required this.maxShutterSpeed,
    required this.lensList,
    required this.formatList,
    // Native API 由来・ユーザー操作可
    required this.iso,
    required this.shutterSpeed,
    required this.lens,
    required this.isFocusModeAuto,
    required this.focus,
    required this.zoom,
    required this.format,
    required this.extendedZoom, // Lens, Zoom から間接的に計算する
    this.focusMagnifierEnabled = false,
  });

  CameraState copyWith({
    AnalysisType? analysisType,
    CameraMode? cameraMode,
    ExtendedZoomType? extendedZoom,
    bool? isStabilizationAvailable,
    bool? isTelephotoAvailable,
    List<Lens>? telephotoLensList,
    List<Lens>? wideAngleLensList,
    double? longsideAngleOfView,
    double? minZoom,
    double? maxZoom,
    double? minFocus,
    double? maxFocus,
    double? minISO,
    double? maxISO,
    double? minShutterSpeed,
    double? maxShutterSpeed,
    List<Lens>? lensList,
    List<Format>? formatList,
    double? iso,
    double? shutterSpeed,
    Lens? lens,
    bool? isFocusModeAuto,
    double? focus,
    double? zoom,
    Format? format,
    bool? focusMagnifierEnabled,
  }) {
    return CameraState(
      analysisType: analysisType ?? this.analysisType,
      cameraMode: cameraMode ?? this.cameraMode,
      extendedZoom: extendedZoom ?? this.extendedZoom,
      isStabilizationAvailable:
          isStabilizationAvailable ?? this.isStabilizationAvailable,
      isTelephotoAvailable: isTelephotoAvailable ?? this.isTelephotoAvailable,
      telephotoLensList: telephotoLensList ?? this.telephotoLensList,
      wideAngleLensList: wideAngleLensList ?? this.wideAngleLensList,
      longsideAngleOfView: longsideAngleOfView ?? this.longsideAngleOfView,
      minZoom: minZoom ?? this.minZoom,
      maxZoom: maxZoom ?? this.maxZoom,
      minFocus: minFocus ?? this.minFocus,
      maxFocus: maxFocus ?? this.maxFocus,
      minISO: minISO ?? this.minISO,
      maxISO: maxISO ?? this.maxISO,
      minShutterSpeed: minShutterSpeed ?? this.minShutterSpeed,
      maxShutterSpeed: maxShutterSpeed ?? this.maxShutterSpeed,
      lensList: lensList ?? this.lensList,
      formatList: formatList ?? this.formatList,
      iso: iso ?? this.iso,
      shutterSpeed: shutterSpeed ?? this.shutterSpeed,
      lens: lens ?? this.lens,
      isFocusModeAuto: isFocusModeAuto ?? this.isFocusModeAuto,
      focus: focus ?? this.focus,
      zoom: zoom ?? this.zoom,
      format: format ?? this.format,
      focusMagnifierEnabled:
          focusMagnifierEnabled ?? this.focusMagnifierEnabled,
    );
  }
}

@Riverpod()
class CameraController extends _$CameraController with WidgetsBindingObserver {
  CameraController({
    KnowhereConfigurableCamera? cameraAPI,
  }) : cameraAPI = cameraAPI ?? KnowhereConfigurableCamera.getSingletonObject();

  final _logger = FimberLog('CameraController');

  final KnowhereConfigurableCamera cameraAPI;
  late final ProfileStorage profileStorage;
  RecordingSession? _currentSession;

  Timer? _paramUpdateTimer;
  bool _timerStarted = false;
  bool _isAutoExposure = false;

  @override
  CameraState build() {
    profileStorage = ref.watch(profileStorageProvider);

    // WidgetsBindingObserver登録
    WidgetsBinding.instance.addObserver(this);
    ref.onDispose(() {
      _paramUpdateTimer?.cancel();
      _paramUpdateTimer = null;
      _timerStarted = false;
      WidgetsBinding.instance.removeObserver(this);
      _saveCameraProfileToStorage();
    });
    return CameraState(
      analysisType: AnalysisType.pitching,
      cameraMode: null,
      extendedZoom: null,
      isStabilizationAvailable: false,
      isTelephotoAvailable: null,
      telephotoLensList: [],
      wideAngleLensList: [],
      longsideAngleOfView: null,
      minZoom: null,
      maxZoom: null,
      minFocus: null,
      maxFocus: null,
      minISO: null,
      maxISO: null,
      minShutterSpeed: null,
      maxShutterSpeed: null,
      lensList: null,
      formatList: null,
      iso: null,
      shutterSpeed: null,
      lens: null,
      isFocusModeAuto: null,
      focus: null,
      zoom: null,
      format: null,
    );
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    if (state == AppLifecycleState.paused ||
        state == AppLifecycleState.inactive ||
        state == AppLifecycleState.detached) {
      _saveCameraProfileToStorage();
    }
    super.didChangeAppLifecycleState(state);
  }

  void _saveCameraProfileToStorage() {
    try {
      if (state.focus != null && state.isFocusModeAuto == false) {
        profileStorage.setCameraFocusValue(state.focus!);
        profileStorage.setCameraAutoFocusMode(false);
      }
      if (state.isFocusModeAuto != null) {
        profileStorage.setCameraAutoFocusMode(state.isFocusModeAuto!);
      }
    } catch (e, stacktrace) {
      _logger.e('Failed to save camera profile to storage',
          ex: e, stacktrace: stacktrace);
    }
  }

  void _startParamUpdateTimer() {
    try {
      if (_paramUpdateTimer != null) return; // 多重起動防止
      _paramUpdateTimer =
          Timer.periodic(const Duration(milliseconds: 500), (_) async {
        final (
          iso,
          shutterSpeed,
          focus,
          zoom,
          longsideAngleOfView,
          focusMangifierEnabled
        ) = await (
          getISO(),
          getShutterSpeed(),
          getFocus(),
          getZoom(),
          getLongsideAngleOfView(),
          getFocusMagnifierEnabled(),
        ).wait;
        if (iso != state.iso ||
            focus != state.focus ||
            shutterSpeed != state.shutterSpeed ||
            zoom != state.zoom ||
            longsideAngleOfView != state.longsideAngleOfView ||
            focusMangifierEnabled != state.focusMagnifierEnabled) {
          state = state.copyWith(
            iso: iso,
            shutterSpeed: shutterSpeed,
            focus: focus,
            zoom: zoom,
            longsideAngleOfView: longsideAngleOfView,
            focusMagnifierEnabled: focusMangifierEnabled,
          );
        }
      });
    } catch (e, stacktrace) {
      _logger.e('Failed to start param update timer',
          ex: e, stacktrace: stacktrace);
    }
  }

  Future<String?> initializeRecordingDirectory(
    String sessionId,
    DateTime sessionCreatedAt,
  ) async {
    try {
      // sessionDate を使って recordingDirectory を組み立てる
      final sessionDate = sessionCreatedAt
          .toUtc() // assumes UTC
          .toIso8601String()
          .split('T')
          .first;
      final baseDir = await LocalVideoData.getBaseDirectory();
      _currentSession = RecordingSession(
        sessionId: sessionId,
        directory: join(baseDir, 'videos', '$sessionDate.$sessionId'),
      );
      return _currentSession!.directory;
    } catch (e, stacktrace) {
      _logger.e(
        'Failed to init recording directory',
        ex: e,
        stacktrace: stacktrace,
      );
      return null;
    }
  }

  Future<int?> configureSession(VoidCallback? onVolumeKeyPressed) async {
    try {
      // The `knowhere_configurable_camera` library does not manage camera permission.
      // So this project leverages `permission_handler` library to handle camera permission.
      final isPermissionGranted = await Permission.camera.request().isGranted;
      if (!isPermissionGranted) {
        _logger.w('Camera permission is not granted');
        return null;
      }

      _logger.i('Camera permission is granted');

      final cameraId = await cameraAPI.configureSession(
        onVolumeKeyPressed: onVolumeKeyPressed,
      );

      _logger.i('Camera session configured with ID: $cameraId');

      // 主要なカメラパラメータを一括取得してstateを更新
      await _updateNativeParameters();

      _logger.i('Camera parameters updated');

      if (isIos) {
        await _setPreferences();
        _logger.i('Camera preferences set');
      } else {
        await cameraAPI.setFocusModeToAuto();
        if (state.isStabilizationAvailable == true) {
          await setStabilizationModeOn();
        }
      }

      if (!_timerStarted) {
        _startParamUpdateTimer();
        _timerStarted = true;
      }

      return cameraId;
    } catch (e, stacktrace) {
      _logger.e('Failed to configure session', ex: e, stacktrace: stacktrace);
      return null;
    }
  }

  Future<void> _updateNativeParameters() async {
    final (
      iso,
      shutterSpeed,
      lens,
      isFocusModeAuto,
      focus,
      zoom,
      format,
      minZoom,
      maxZoom,
    ) = await (
      getISO(),
      getShutterSpeed(),
      getLensIndex().then((idx) async {
        final lensList = await getLensList();
        if (lensList != null &&
            idx != null &&
            idx >= 0 &&
            idx < lensList.length) {
          return lensList[idx];
        }
        return null;
      }),
      isAutoFocus(),
      getFocus(),
      getZoom(),
      getFormatIndex().then((idx) async {
        final formatList = await getFormatList();
        if (formatList != null &&
            idx != null &&
            idx >= 0 &&
            idx < formatList.length) {
          return formatList[idx];
        }
        return null;
      }),
      getMinZoom(),
      getMaxZoom(),
    ).wait;

    final (
      minFocus,
      maxFocus,
      minISO,
      maxISO,
      minShutterSpeed,
      maxShutterSpeed,
      lensList,
      formatList,
    ) = await (
      getMinFocus(),
      getMaxFocus(),
      getMinISO(),
      getMaxISO(),
      getMinShutterSpeed(),
      getMaxShutterSpeed(),
      getLensList(),
      getFormatList(),
    ).wait;

    // 追加: NativeParametersの全更新
    final isStabilizationAvailable = await isStabilizationSupportedDevice();
    final telephotoLensList = lensList == null
        ? <Lens>[]
        : lensList.where((lens) => lens.isTelephoto).toList();
    final wideAngleLensList = lensList == null
        ? <Lens>[]
        : lensList.where((lens) => lens.isWideAngle).toList();
    final isTelephotoAvailable = telephotoLensList.isNotEmpty;

    final extendedZoom =
        (lens != null && zoom != null && minZoom != null && maxZoom != null)
            ? ExtendedZoomType.fromLensAndZoom(
                currentLens: lens,
                currentZoom: zoom,
                minZoom: minZoom,
                maxZoom: maxZoom,
              )
            : null;

    state = state.copyWith(
      minZoom: minZoom,
      maxZoom: maxZoom,
      minFocus: minFocus,
      maxFocus: maxFocus,
      minISO: minISO,
      maxISO: maxISO,
      minShutterSpeed: minShutterSpeed,
      maxShutterSpeed: maxShutterSpeed,
      lensList: lensList,
      formatList: formatList,
      iso: iso,
      shutterSpeed: shutterSpeed,
      lens: lens,
      isFocusModeAuto: isFocusModeAuto,
      focus: focus,
      zoom: zoom,
      extendedZoom: extendedZoom,
      format: format,
      // 追加分
      isStabilizationAvailable: isStabilizationAvailable,
      telephotoLensList: telephotoLensList,
      wideAngleLensList: wideAngleLensList,
      isTelephotoAvailable: isTelephotoAvailable,
    );
  }

  Future<void> closeSession() async {
    try {
      _paramUpdateTimer?.cancel();
      _paramUpdateTimer = null;
      _timerStarted = false;

      final accelerationController =
          AccelerationController.getSingletonObject();
      if (accelerationController.isWorking) {
        accelerationController.stop();
      }

      if (_currentSession?.recordingFilePath != null) {
        await File(_currentSession!.recordingFilePath!).delete();
        _currentSession!.recordingFilePath = null;
      }

      await cameraAPI.closeSession();
      _currentSession = null;
    } catch (e, stacktrace) {
      _logger.e('Failed to close session', ex: e, stacktrace: stacktrace);
    }
  }

  Future getOrientationAngle() async {
    try {
      return cameraAPI.getOrientationAngle();
    } catch (e, stacktrace) {
      _logger.e('Failed to get orientation angle',
          ex: e, stacktrace: stacktrace);
    }
  }

  Future<void> _setPreferences() async {
    await setCameraModeAuto();
    await _setSavedFocus();

    // NOTE: Stabilization is always on.
    await setStabilizationModeOn();

    final intAnalysisType = profileStorage.getCameraAnalysisType();
    if (intAnalysisType != null) {
      state = state.copyWith(
        analysisType: AnalysisType.fromValue(intAnalysisType),
      );
    }
  }

  Future<void> _setSavedFocus() async {
    final autoFocusMode = profileStorage.getCameraAutoFocusMode();
    // 以前 AF だった or autoFocusMode が保存されていない場合は AF にする
    if (autoFocusMode == true || autoFocusMode == null) {
      await cameraAPI.setFocusModeToAuto();
      return;
    }

    final focusValue = profileStorage.getCameraFocusValue();
    await setFocusModeToManual();
    if (focusValue != null) {
      await setFocus(focusValue);
    }
  }

  Future<String> connect() async {
    try {
      return cameraAPI.connect();
    } catch (e, stacktrace) {
      _logger.e('Failed to connect', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<bool?> isSupportedDevice() async {
    try {
      return cameraAPI.isSupportedDevice();
    } catch (e, stacktrace) {
      _logger.e(
        'Failed to check if device is supported',
        ex: e,
        stacktrace: stacktrace,
      );
      rethrow;
    }
  }

  Future<bool?> isStabilizationSupportedDevice() async {
    try {
      return cameraAPI.isStabilizationSupportedDevice();
    } catch (e, stacktrace) {
      _logger.e(
        'Failed to check if device is supported',
        ex: e,
        stacktrace: stacktrace,
      );
      rethrow;
    }
  }

  Future<bool> onPause() async {
    try {
      return cameraAPI.onPause();
    } catch (e, stacktrace) {
      _logger.e('Failed to onPause', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<bool> onResume() async {
    try {
      return cameraAPI.onResume();
    } catch (e, stacktrace) {
      _logger.e('Failed to onResume', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  /// Sanitize file names when saving locally.
  String _sanitizeRecordingFileName(String fileName) => sanitizeFilename(
        fileName.replaceAll(':', '-'),
        replacement: '_',
      );

  Future<String?> startRecording() async {
    try {
      _isAutoExposure = await isAutoExposure();
      await tearDownAutoExposureObserver();

      if (_currentSession == null) {
        throw Exception();
      }

      final accelerationController =
          AccelerationController.getSingletonObject();
      final orientation = await NativeDeviceOrientationCommunicator()
          .orientation(useSensor: false);
      accelerationController.setOrientation(orientation);

      final now = DateTime.now(); // NOTE: It's local time
      final fileName = now
          .toString()
          .replaceAll(' ', '_'); // extension is decided by native side.
      await Directory(_currentSession!.directory).create(recursive: true);
      final filePath = join(
          _currentSession!.directory, _sanitizeRecordingFileName(fileName));

      accelerationController.reset();
      accelerationController.start();

      _currentSession!.recordingFilePath =
          await cameraAPI.startRecording(filePath);
      return _currentSession!.recordingFilePath;
    } catch (e, stacktrace) {
      _logger.e('Failed to start recording', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<void> stopRecordingForCancel() async {
    try {
      if (_currentSession == null ||
          _currentSession!.recordingFilePath == null) {
        throw Exception();
      }
      await cameraAPI.stopRecording();

      final accelerationController =
          AccelerationController.getSingletonObject();
      accelerationController.stop();

      // NOTE: The method cameraAPI.stopRecording returns before completes saving a video file.
      // TODO: Refactor knowhere_configurable_camera to wait completing.
      await Future.delayed(const Duration(milliseconds: 500), () async {
        if (_currentSession!.recordingFilePath != null) {
          await File(_currentSession!.recordingFilePath!).delete();
          _currentSession!.recordingFilePath = null;
        }
      });
    } catch (e, stacktrace) {
      _logger.e('Failed to stop recording for cancel',
          ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<LocalVideoData> stopRecordingAndSaveToLocalStorage(
    UnitType unit,
  ) async {
    try {
      setUpAutoExposureObserver();

      if (_currentSession == null ||
          _currentSession!.recordingFilePath == null) {
        throw Exception();
      }
      await cameraAPI.stopRecording();

      final accelerationController =
          AccelerationController.getSingletonObject();
      accelerationController.stop();

      final longsideAngleOfView = await getLongsideAngleOfView();
      assert(longsideAngleOfView != null);
      final accX = accelerationController.averageX;
      final accY = accelerationController.averageY;
      final accZ = accelerationController.averageZ;
      final lensList = await getLensList();
      final lensIndex =
          (await getLensIndex())?.clamp(0, (lensList?.length ?? 1) - 1);
      final lens =
          (lensList != null && lensIndex != null) ? lensList[lensIndex] : null;

      final (focus, isAutoFocus, zoom, iso, shutterSpeed) = await (
        getFocus(),
        this.isAutoFocus(),
        getZoom(),
        getISO(),
        getShutterSpeed(),
      ).wait;

      ExtendedZoomType? extendedZoomType;
      if (lens != null &&
          zoom != null &&
          state.minZoom != null &&
          state.maxZoom != null) {
        extendedZoomType = ExtendedZoomType.fromLensAndZoom(
          currentLens: lens,
          currentZoom: zoom,
          minZoom: state.minZoom!,
          maxZoom: state.maxZoom!,
        );
      }

      final deviceInfo = DeviceInfoPlugin();
      final device = platform.isAndroid
          ? (await deviceInfo.androidInfo).model
          : (await deviceInfo.iosInfo).utsname.fixedProductName();

      final localVideoListController =
          ref.read(localVideoListControllerProvider.notifier);
      LocalVideoData? newData;

      final teamId = profileStorage.getTeamId()!;

      // NOTE: The method cameraAPI.stopRecording returns before completes saving a video file.
      // TODO: Refactor knowhere_configurable_camera to wait completing.
      await Future.delayed(const Duration(milliseconds: 500), () async {
        newData = await localVideoListController.addFile(
          sessionId: _currentSession!.sessionId,
          teamId: teamId,
          filePath: _currentSession!.recordingFilePath!,
          analyzeType: state.analysisType.value,
          unit: unit,
          focalLengthIn35mmEquivalent: null,
          longsideAngleOfView: longsideAngleOfView!,
          accX: accX,
          accY: accY,
          accZ: accZ,
          lens: lens?.description,
          cameraMode:
              '${extendedZoomType == null ? '-' : extendedZoomType.name}+${state.cameraMode == null ? '-' : state.cameraMode!.name}${_isAutoExposure ? ' (AE)' : ''}',
          focus: focus,
          isAutoFocus: isAutoFocus,
          zoom: zoom,
          iso: iso,
          shutterSpeed: shutterSpeed,
          device: device,
        );
      });

      _currentSession!.recordingFilePath = null;

      return newData!;
    } catch (e, stacktrace) {
      _logger.e('Failed to stop recording and save to local storage',
          ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

