  Future<void> setExtendedZoomType(ExtendedZoomType extendedZoomType) async {
    try {
      int targetLensIndex;
      double targetZoom;

      switch (extendedZoomType) {
        case ExtendedZoomType.superZoom:
          // Telephoto × max zoom
          if (state.telephotoLensList.isEmpty) {
            throw Exception('Telephoto lens not available for superZoom');
          }
          targetLensIndex = state.telephotoLensList.first.index;
          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
          break;
        case ExtendedZoomType.zoom:
          // Telephoto × min zoom
          if (state.telephotoLensList.isEmpty) {
            throw Exception('Telephoto lens not available for zoom');
          }
          targetLensIndex = state.telephotoLensList.first.index;
          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
          break;
        case ExtendedZoomType.wide:
          // WideAngle × max zoom
          if (state.wideAngleLensList.isEmpty) {
            throw Exception('WideAngle lens not available for wide');
          }
          targetLensIndex = state.wideAngleLensList.first.index;
          targetZoom = state.maxZoom ?? CameraState.defaultMaxZoom;
          break;
        case ExtendedZoomType.superWide:
          // WideAngle × min zoom
          if (state.wideAngleLensList.isEmpty) {
            throw Exception('WideAngle lens not available for superWide');
          }
          targetLensIndex = state.wideAngleLensList.first.index;
          targetZoom = state.minZoom ?? CameraState.defaultMinZoom;
          break;
      }

      // Save to profileStorage
      profileStorage.setCameraExtendedZoomType(extendedZoomType);

      // Apply settings (lens first, then zoom)
      await setLensIndex(targetLensIndex);
      await setZoom(targetZoom);

      // Update state
      state = state.copyWith(extendedZoom: extendedZoomType);
    } catch (e, stacktrace) {
      _logger.e('Failed to set extended zoom type',
          ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<String> setLensIndex(int index) async {
    try {
      final message = await cameraAPI.setLensIndex(index);
      await _updateNativeParameters();

      final lensList = state.lensList;
      if (index >= 0 && index < lensList!.length) {
        state = state.copyWith(lens: lensList[index]);
      }
      // Stabilization mode is sometimes turned off by iOS when it changes its lens.
      if (state.isStabilizationAvailable == true) {
        await setStabilizationModeOn();
      }

      setUpAutoExposureObserver();

      return message;
    } catch (e, stacktrace) {
      _logger.e('Failed to set lens index', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<String> setFormatIndex(int index) async {
    try {
      final message = await cameraAPI.setFormatIndex(index);
      await _updateNativeParameters();

      final formatList = state.formatList;
      if (formatList != null && index >= 0 && index < formatList.length) {
        state = state.copyWith(format: formatList[index]);
      }
      // Stabilization mode is sometimes turned off by iOS when it changes its format.
      if (state.isStabilizationAvailable == true) {
        await setStabilizationModeOn();
      }
      return message;
    } catch (e, stacktrace) {
      _logger.e('Failed to set format index', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<void> setCameraModeAuto() async {
    try {
      if (!isTestEnvironment && !platform.isIos) return;

      state = state.copyWith(cameraMode: CameraMode.auto);

      final savedExtendedZoomType = profileStorage.getCameraExtendedZoomType();
      final extendedZoomType = savedExtendedZoomType ??
          (state.isTelephotoAvailable == true
              ? ExtendedZoomType.zoom
              : ExtendedZoomType.wide);

      final formatFullHD60FPS = await getBestFormat();
      assert(formatFullHD60FPS != null);
      await setFormatIndex(formatFullHD60FPS!.index);

      // format 変更後にzoomを設定
      await setExtendedZoomType(extendedZoomType);

      // Set shutter speed
      await setShutterSpeed(4000);

      // Set Initial ISO to 1000
      await setISO(1000);
      setUpAutoExposureObserver();
    } catch (e, stacktrace) {
      _logger.e('Failed to set bright mode', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  void setManualMode() {
    try {
      if (!isTestEnvironment && !platform.isIos) return;

      state = state.copyWith(cameraMode: CameraMode.manual);
    } catch (e, stacktrace) {
      _logger.e('Failed to set manual mode', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<void> setAnalysisType(AnalysisType analysisType) async {
    try {
      // Check if current extended zoom is SuperWide and new analysis type is pitching-related
      final currentExtendedZoom = state.extendedZoom;
      final isPitchingRelated = analysisType == AnalysisType.pitching ||
          analysisType == AnalysisType.both ||
          analysisType == AnalysisType.pitchingAll;

      state = state.copyWith(analysisType: analysisType);
      profileStorage.setCameraAnalysisType(analysisType.value);

      // If currently in SuperWide mode and switching to pitching-related analysis,
      // automatically switch to Wide mode
      if (currentExtendedZoom == ExtendedZoomType.superWide &&
          isPitchingRelated) {
        await setExtendedZoomType(ExtendedZoomType.wide);
      }
    } catch (e, stacktrace) {
      _logger.e('Failed to set analysis type', ex: e, stacktrace: stacktrace);
      rethrow;
    }
  }

  Future<void> tearDownAutoExposureObserver() async {
    // テスト環境や Android では Exposure の自動調整をしない
    if (isTestEnvironment || isAndroid) return;
    await cameraAPI.tearDownAutoExposureObserver();
  }

  Future<void> setUpAutoExposureObserver() async {
    // テスト環境や Android では Exposure の自動調整をしない
    if (isTestEnvironment || isAndroid) return;
    await cameraAPI.setUpAutoExposureObserver();
  }

  Future<bool> isAutoExposure() async {
    // テスト環境や Android では Exposure の自動調整をしない
    if (isTestEnvironment || isAndroid) return false;
    return await cameraAPI.isAutoExposure() ?? false;
  }

  @visibleForTesting
  void setCameraState(CameraState cameraState) {
    state = cameraState;
  }
}

