// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/enums/extended_zoom_type.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';

String Function(ExtendedZoomType?) useExtendedZoomTypeName(
    {bool hasBlank = false}) {
  final context = useContext();
  return (ExtendedZoomType? extendedZoomType) {
    return switch (extendedZoomType) {
      ExtendedZoomType.superZoom => hasBlank
          ? context
              .l10n.recording_page__extended_zoom_type_super_zoom_with_blank
          : context.l10n.recording_page__extended_zoom_type_super_zoom,
      ExtendedZoomType.zoom =>
        context.l10n.recording_page__extended_zoom_type_zoom,
      ExtendedZoomType.wide =>
        context.l10n.recording_page__extended_zoom_type_wide,
      ExtendedZoomType.superWide => hasBlank
          ? context
              .l10n.recording_page__extended_zoom_type_super_wide_with_blank
          : context.l10n.recording_page__extended_zoom_type_super_wide,
      _ => '-',
    };
  };
}

