group('determineExtendedZoomType - 境界値テスト', () {
  test('should handle zoom values very close to max zoom', () {
    final lens = Lens(0, 'Telephoto');

    final result = ExtendedZoomType.fromLensAndZoom(
      currentLens: lens,
      currentZoom: 1.994, // rounds to 1.99
      maxZoom: CameraState.defaultMaxZoom, // 1.99
